  4→// ──────────────────────────────────────────────────────
  5→// Helpers
  6→// ──────────────────────────────────────────────────────
  7→
  8→/**
  9→ * Safely parse the models_used JSON column.
 10→ * Returns undefined on any parse failure rather than throwing — a corrupt
 11→ * value in one row should not break the entire query.
 12→ */
 13→function parseModelsUsed(raw: string | null): string[] | undefined {
 14→  if (!raw) return undefined;
 15→  try {
 16→    return JSON.parse(raw) as string[];
 17→  } catch {
 18→    return undefined;
 19→  }
 20→}
