 26→export function sessionExists(sessionId: string): boolean {
 27→  const db = getDb();
 28→  const row = db.prepare('SELECT 1 FROM sessions WHERE id = ?').get(sessionId) as { 1: number } | undefined;
 29→  return row !== undefined;
 30→}
