 57→export interface SessionQueryOptions {
 58→  periodStart?: Date;
 59→  projectId?: string;
 60→  sourceTool?: string;
 61→}
 62→
 63→/**
 64→ * Query sessions from SQLite, mapping snake_case columns to SessionRow shape.
 65→ */
 66→export function getSessions(opts: SessionQueryOptions = {}): SessionRow[] {
 67→  const db = getDb();
 68→
 69→  const conditions: string[] = [];
 70→  const params: (string | number)[] = [];
 71→
 72→  if (opts.periodStart) {
 73→    conditions.push('started_at >= ?');
 74→    params.push(opts.periodStart.toISOString());
 75→  }
 76→  if (opts.projectId) {
 77→    conditions.push('project_id = ?');
 78→    params.push(opts.projectId);
 79→  }
 80→  if (opts.sourceTool) {
 81→    conditions.push('source_tool = ?');
 82→    params.push(opts.sourceTool);
 83→  }
 84→
 85→  const where = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
 86→  const sql = `
 87→    SELECT
 88→      id, project_id, project_name,
 89→      started_at, ended_at,
 90→      message_count, user_message_count, assistant_message_count, tool_call_count,
 91→      estimated_cost_usd, total_input_tokens, total_output_tokens,
 92→      cache_creation_tokens, cache_read_tokens,
 93→      primary_model, models_used,
 94→      generated_title, custom_title, summary, session_character,
 95→      source_tool, usage_source
 96→    FROM sessions
 97→    ${where}
 98→    ORDER BY started_at DESC
 99→  `;
100→
101→  const rows = db.prepare(sql).all(...params) as Array<{
102→    id: string;
103→    project_id: string;
104→    project_name: string;
105→    started_at: string;
106→    ended_at: string;
107→    message_count: number;
108→    user_message_count: number;
109→    assistant_message_count: number;
110→    tool_call_count: number;
111→    estimated_cost_usd: number | null;
112→    total_input_tokens: number | null;
113→    total_output_tokens: number | null;
114→    cache_creation_tokens: number | null;
115→    cache_read_tokens: number | null;
116→    primary_model: string | null;
117→    models_used: string | null;
118→    generated_title: string | null;
119→    custom_title: string | null;
120→    summary: string | null;
121→    session_character: string | null;
122→    source_tool: string; // NOT NULL in schema, DEFAULT 'claude-code'
123→    usage_source: string | null;
124→  }>;
125→
126→  return rows.map((r) => ({
127→    id: r.id,
128→    projectId: r.project_id,
129→    projectName: r.project_name,
130→    startedAt: new Date(r.started_at),
131→    endedAt: new Date(r.ended_at),
132→    messageCount: r.message_count,
133→    userMessageCount: r.user_message_count,
134→    assistantMessageCount: r.assistant_message_count,
135→    toolCallCount: r.tool_call_count,
136→    estimatedCostUsd: r.estimated_cost_usd ?? undefined,
137→    totalInputTokens: r.total_input_tokens ?? undefined,
138→    totalOutputTokens: r.total_output_tokens ?? undefined,
139→    cacheCreationTokens: r.cache_creation_tokens ?? undefined,
140→    cacheReadTokens: r.cache_read_tokens ?? undefined,
141→    primaryModel: r.primary_model ?? undefined,
142→    modelsUsed: parseModelsUsed(r.models_used),
143→    generatedTitle: r.generated_title ?? undefined,
144→    customTitle: r.custom_title ?? undefined,
145→    summary: r.summary ?? undefined,
146→    sessionCharacter: r.session_character ?? undefined,
147→    sourceTool: r.source_tool,
148→    usageSource: r.usage_source ?? undefined,
149→  }));
150→}
