  1→import { getDb } from './client.js';
  2→import { sessionExists } from './read.js';
  3→import { generateStableProjectId, getDeviceInfo } from '../utils/device.js';
  4→import type { ParsedSession, ParsedMessage } from '../types.js';
  5→import type BetterSqlite3 from 'better-sqlite3';
  6→
  7→const CONTENT_MAX = 10000;
  8→const THINKING_MAX = 5000;
  9→const TOOL_RESULT_MAX = 2000;
 10→const TOOL_INPUT_MAX = 1000;
 11→
 12→function truncate(s: string, max: number): string {
 13→  if (s.length <= max) return s;
 14→  return s.slice(0, max - 20) + '\n... [truncated]';
 15→}
