 17→// ──────────────────────────────────────────────────────
 18→// Module-level lazy-initialized prepared statements.
 19→//
 20→// We can't prepare at module load time because the DB isn't open yet.
 21→// Instead, we lazy-init on first use — a statement is compiled once and
 22→// reused on every subsequent call, avoiding repeated parse overhead during
 23→// batch syncs that write hundreds of sessions.
 24→// ──────────────────────────────────────────────────────
 25→
 26→let _lastDb: BetterSqlite3.Database | null = null;
 27→
 28→// All cached statements below — reset when DB instance changes (e.g., test teardown)
 29→let _stmtUpsertProjectBase: BetterSqlite3.Statement | null = null;
 30→let _stmtUpdateProjectWithUsage: BetterSqlite3.Statement | null = null;
 31→let _stmtUpdateProjectCountOnly: BetterSqlite3.Statement | null = null;
 32→let _stmtUpsertSession: BetterSqlite3.Statement | null = null;
 33→let _stmtInsertMessage: BetterSqlite3.Statement | null = null;
 34→let _stmtUpsertUsageStatsIncrement: BetterSqlite3.Statement | null = null;
 35→
 36→function getStmts() {
 37→  const db = getDb();
 38→  // If the DB instance changed (test isolation, reset), rebuild all statements
 39→  if (db !== _lastDb) {
 40→    _lastDb = db;
 41→    _stmtUpsertProjectBase = null;
 42→    _stmtUpdateProjectWithUsage = null;
 43→    _stmtUpdateProjectCountOnly = null;
 44→    _stmtUpsertSession = null;
 45→    _stmtInsertMessage = null;
 46→    _stmtUpsertUsageStatsIncrement = null;
 47→  }
 48→
 49→  if (!_stmtUpsertProjectBase) {
 50→    _stmtUpsertProjectBase = db.prepare(`
 51→      INSERT INTO projects (id, name, path, git_remote_url, project_id_source, last_activity)
 52→      VALUES (?, ?, ?, ?, ?, ?)
 53→      ON CONFLICT(id) DO UPDATE SET
 54→        name = excluded.name,
 55→        path = excluded.path,
 56→        git_remote_url = excluded.git_remote_url,
 57→        last_activity = MAX(last_activity, excluded.last_activity),
 58→        updated_at = datetime('now')
 59→    `);
 60→  }
 61→
 62→  if (!_stmtUpdateProjectWithUsage) {
 63→    _stmtUpdateProjectWithUsage = db.prepare(`
 64→      UPDATE projects SET
 65→        session_count         = session_count + 1,
 66→        total_input_tokens    = total_input_tokens + ?,
 67→        total_output_tokens   = total_output_tokens + ?,
 68→        cache_creation_tokens = cache_creation_tokens + ?,
 69→        cache_read_tokens     = cache_read_tokens + ?,
 70→        estimated_cost_usd    = estimated_cost_usd + ?,
 71→        updated_at            = datetime('now')
 72→      WHERE id = ?
 73→    `);
 74→  }
 75→
 76→  if (!_stmtUpdateProjectCountOnly) {
 77→    _stmtUpdateProjectCountOnly = db.prepare(`
 78→      UPDATE projects SET session_count = session_count + 1, updated_at = datetime('now')
 79→      WHERE id = ?
 80→    `);
 81→  }
 82→
 83→  if (!_stmtUpsertSession) {
 84→    _stmtUpsertSession = db.prepare(`
 85→      INSERT INTO sessions (
 86→        id, project_id, project_name, project_path, git_remote_url,
 87→        summary, generated_title, title_source, session_character,
 88→        started_at, ended_at,
 89→        message_count, user_message_count, assistant_message_count, tool_call_count,
 90→        git_branch, claude_version, source_tool,
 91→        device_id, device_hostname, device_platform,
 92→        total_input_tokens, total_output_tokens, cache_creation_tokens, cache_read_tokens,
 93→        estimated_cost_usd, models_used, primary_model, usage_source
 94→      ) VALUES (
 95→        ?, ?, ?, ?, ?,
 96→        ?, ?, ?, ?,
 97→        ?, ?,
 98→        ?, ?, ?, ?,
 99→        ?, ?, ?,
100→        ?, ?, ?,
101→        ?, ?, ?, ?,
102→        ?, ?, ?, ?
103→      )
104→      ON CONFLICT(id) DO UPDATE SET
105→        generated_title         = excluded.generated_title,
106→        title_source            = excluded.title_source,
107→        session_character       = excluded.session_character,
108→        ended_at                = excluded.ended_at,
109→        summary                 = excluded.summary,
110→        message_count           = excluded.message_count,
111→        user_message_count      = excluded.user_message_count,
112→        assistant_message_count = excluded.assistant_message_count,
113→        tool_call_count         = excluded.tool_call_count,
114→        total_input_tokens      = excluded.total_input_tokens,
115→        total_output_tokens     = excluded.total_output_tokens,
116→        cache_creation_tokens   = excluded.cache_creation_tokens,
117→        cache_read_tokens       = excluded.cache_read_tokens,
118→        estimated_cost_usd      = excluded.estimated_cost_usd,
119→        models_used             = excluded.models_used,
120→        primary_model           = excluded.primary_model,
121→        usage_source            = excluded.usage_source,
122→        synced_at               = datetime('now')
123→    `);
124→  }
125→
126→  if (!_stmtInsertMessage) {
127→    _stmtInsertMessage = db.prepare(`
128→      INSERT OR IGNORE INTO messages (
129→        id, session_id, type, content, thinking,
130→        tool_calls, tool_results, usage, timestamp, parent_id
131→      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
132→    `);
133→  }
134→
135→  if (!_stmtUpsertUsageStatsIncrement) {
136→    _stmtUpsertUsageStatsIncrement = db.prepare(`
137→      INSERT INTO usage_stats (id, total_input_tokens, total_output_tokens, cache_creation_tokens, cache_read_tokens, estimated_cost_usd, sessions_with_usage, last_updated_at)
138→      VALUES (1, ?, ?, ?, ?, ?, 1, datetime('now'))
139→      ON CONFLICT(id) DO UPDATE SET
140→        total_input_tokens    = total_input_tokens + excluded.total_input_tokens,
141→        total_output_tokens   = total_output_tokens + excluded.total_output_tokens,
142→        cache_creation_tokens = cache_creation_tokens + excluded.cache_creation_tokens,
143→        cache_read_tokens     = cache_read_tokens + excluded.cache_read_tokens,
144→        estimated_cost_usd    = estimated_cost_usd + excluded.estimated_cost_usd,
145→        sessions_with_usage   = sessions_with_usage + 1,
146→        last_updated_at       = datetime('now')
147→    `);
148→  }
149→
150→  return {
151→    upsertProjectBase: _stmtUpsertProjectBase,
152→    updateProjectWithUsage: _stmtUpdateProjectWithUsage,
153→    updateProjectCountOnly: _stmtUpdateProjectCountOnly,
154→    upsertSession: _stmtUpsertSession,
155→    insertMessage: _stmtInsertMessage,
156→    upsertUsageStatsIncrement: _stmtUpsertUsageStatsIncrement,
157→  };
158→}
