160→/**
161→ * Upsert project record and insert session + messages.
162→ * Replaces firebase/client.ts uploadSession() + uploadMessages().
163→ *
164→ * isForce: when true (--force sync), usage stats on the project are NOT
165→ * incrementally added — they'll be recalculated via recalculateUsageStats().
166→ */
167→export function insertSessionWithProject(session: ParsedSession, isForce = false): void {
168→  insertSessionWithProjectInternal(session, isForce);
169→}
170→
171→/**
172→ * Insert a session and return whether it was new to the DB.
173→ * Lets callers avoid a duplicate sessionExists() query.
174→ */
175→export function insertSessionWithProjectAndReturnIsNew(session: ParsedSession, isForce = false): boolean {
176→  return insertSessionWithProjectInternal(session, isForce);
177→}
178→
179→function insertSessionWithProjectInternal(session: ParsedSession, isForce: boolean): boolean {
180→  const db = getDb();
181→  const { projectId, source: projectIdSource, gitRemoteUrl } = generateStableProjectId(session.projectPath);
182→  const deviceInfo = getDeviceInfo();
183→
184→  const isNew = !sessionExists(session.id);
185→
186→  const tx = db.transaction(() => {
187→    upsertProject(projectId, session, projectIdSource, gitRemoteUrl, isNew, isForce);
188→    upsertSession(session, projectId, gitRemoteUrl, deviceInfo);
189→    if (isNew) {
190→      updateGlobalUsageStats(session, isForce);
191→    }
192→  });
193→
194→  tx();
195→  return isNew;
196→}
