198→
199→function upsertProject(
200→  projectId: string,
201→  session: ParsedSession,
202→  projectIdSource: string,
203→  gitRemoteUrl: string | null,
204→  isNewSession: boolean,
205→  isForce: boolean,
206→): void {
207→  const stmts = getStmts();
208→
209→  // Insert project if it doesn't exist
210→  stmts.upsertProjectBase.run(
211→    projectId,
212→    session.projectName,
213→    session.projectPath,
214→    gitRemoteUrl,
215→    projectIdSource,
216→    session.endedAt.toISOString(),
217→  );
218→
219→  // Increment session count and usage only for genuinely new sessions
220→  if (isNewSession && !isForce && session.usage) {
221→    stmts.updateProjectWithUsage.run(
222→      session.usage.totalInputTokens,
223→      session.usage.totalOutputTokens,
224→      session.usage.cacheCreationTokens,
225→      session.usage.cacheReadTokens,
226→      session.usage.estimatedCostUsd,
227→      projectId,
228→    );
229→  } else if (isNewSession) {
230→    stmts.updateProjectCountOnly.run(projectId);
231→  }
232→}
