234→function upsertSession(
235→  session: ParsedSession,
236→  projectId: string,
237→  gitRemoteUrl: string | null,
238→  deviceInfo: { deviceId: string; hostname: string; platform: string },
239→): void {
240→  const stmts = getStmts();
241→  stmts.upsertSession.run(
242→    session.id,
243→    projectId,
244→    session.projectName,
245→    session.projectPath,
246→    gitRemoteUrl,
247→    session.summary,
248→    session.generatedTitle,
249→    session.titleSource,
250→    session.sessionCharacter,
251→    session.startedAt.toISOString(),
252→    session.endedAt.toISOString(),
253→    session.messageCount,
254→    session.userMessageCount,
255→    session.assistantMessageCount,
256→    session.toolCallCount,
257→    session.gitBranch,
258→    session.claudeVersion,
259→    session.sourceTool ?? 'claude-code',
260→    deviceInfo.deviceId,
261→    deviceInfo.hostname,
262→    deviceInfo.platform,
263→    session.usage?.totalInputTokens ?? null,
264→    session.usage?.totalOutputTokens ?? null,
265→    session.usage?.cacheCreationTokens ?? null,
266→    session.usage?.cacheReadTokens ?? null,
267→    session.usage?.estimatedCostUsd ?? null,
268→    session.usage?.modelsUsed ? JSON.stringify(session.usage.modelsUsed) : null,
269→    session.usage?.primaryModel ?? null,
270→    session.usage?.usageSource ?? null,
271→  );
272→}
