274→/**
275→ * Insert messages for a session.
276→ * Replaces firebase/client.ts uploadMessages().
277→ */
278→export function insertMessages(session: ParsedSession): void {
279→  if (session.messages.length === 0) return;
280→
281→  const db = getDb();
282→  const stmts = getStmts();
283→
284→  const tx = db.transaction((messages: ParsedMessage[]) => {
285→    for (const msg of messages) {
286→      stmts.insertMessage.run(
287→        msg.id,
288→        msg.sessionId,
289→        msg.type,
290→        truncate(msg.content, CONTENT_MAX),
291→        msg.thinking ? truncate(msg.thinking, THINKING_MAX) : null,
292→        msg.toolCalls.length > 0
293→          ? JSON.stringify(msg.toolCalls.map(tc => ({
294→              id: tc.id,
295→              name: tc.name,
296→              input: JSON.stringify(tc.input).slice(0, TOOL_INPUT_MAX),
297→            })))
298→          : null,
299→        msg.toolResults.length > 0
300→          ? JSON.stringify(msg.toolResults.map(tr => ({
301→              toolUseId: tr.toolUseId,
302→              output: truncate(tr.output, TOOL_RESULT_MAX),
303→            })))
304→          : null,
305→        msg.usage ? JSON.stringify(msg.usage) : null,
306→        msg.timestamp.toISOString(),
307→        msg.parentId,
308→      );
309→    }
310→  });
311→
312→  tx(session.messages);
313→}
