345→// POST /api/analysis/recurring
346→// Body: { projectId?: string; limit?: number }
347→// Finds recurring insight patterns across sessions.
348→app.post('/recurring', async (c) => {
349→  if (!isLLMConfigured()) {
350→    return c.json({
351→      success: false,
352→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
353→    }, 400);
354→  }
355→
356→  const body = await c.req.json<{ projectId?: string; limit?: number }>();
357→  const db = getDb();
358→
359→  const conditions: string[] = [];
360→  const params: (string | number)[] = [];
361→
362→  if (body.projectId) {
363→    conditions.push('project_id = ?');
364→    params.push(body.projectId);
365→  }
366→
367→  const where = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
368→  const limit = Math.min(parseIntParam(String(body.limit ?? ''), 200), 200);
369→
370→  const insights = db.prepare(`
371→    SELECT id, type, title, summary, project_name, session_id
372→    FROM insights
373→    ${where}
374→    ORDER BY timestamp DESC
375→    LIMIT ?
376→  `).all(...params, limit) as Array<{
377→    id: string;
378→    type: string;
379→    title: string;
380→    summary: string;
381→    project_name: string;
382→    session_id: string;
383→  }>;
384→
385→  const llmConfig = loadLLMConfig();
386→  const recurringStart = Date.now();
387→  const result = await findRecurringInsights(insights);
388→  const recurringBaseProperties = {
389→    type: 'recurring',
390→    llm_provider: llmConfig?.provider,
391→    llm_model: llmConfig?.model,
392→    duration_ms: Date.now() - recurringStart,
393→    success: result.success,
394→  };
395→  if (!result.success) {
396→    const recurringErrorProperties = {
397→      ...recurringBaseProperties,
398→      error_type: 'api_error',
399→      error_message: result.error,
400→    };
401→    trackEvent('analysis_run', recurringErrorProperties);
402→    captureError(new Error(result.error ?? 'recurring insights failed'), recurringErrorProperties);
403→  } else {
404→    trackEvent('analysis_run', recurringBaseProperties);
405→    trackEvent('insight_generated', {
406→      type: 'recurring',
407→      count: result.groups.length,
408→    });
409→  }
410→  return c.json(result, result.success ? 200 : 422);
411→});
