 42→function getDateGroup(dateStr: string): string {
 43→  const date = new Date(dateStr);
 44→  const now = new Date();
 45→  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
 46→  const yesterday = new Date(today);
 47→  yesterday.setDate(yesterday.getDate() - 1);
 48→  const thisWeekStart = new Date(today);
 49→  thisWeekStart.setDate(thisWeekStart.getDate() - 7);
 50→
 51→  const sessionDay = new Date(date.getFullYear(), date.getMonth(), date.getDate());
 52→
 53→  if (sessionDay.getTime() === today.getTime()) return 'Today';
 54→  if (sessionDay.getTime() === yesterday.getTime()) return 'Yesterday';
 55→  if (sessionDay >= thisWeekStart) return 'This Week';
 56→  return 'Earlier';
 57→}
 58→
 59→const GROUP_ORDER = ['Today', 'Yesterday', 'This Week', 'Earlier'];
 60→
 61→export default function SessionsPage() {
 62→  const [search, setSearch] = useState('');
 63→  const [projectFilter, setProjectFilter] = useState('all');
