 69→
 70→
 71→  const sessionParams = useMemo(() => {
 72→    const params: { projectId?: string; sourceTool?: string; limit?: number } = { limit: 200 };
 73→    if (projectFilter !== 'all') params.projectId = projectFilter;
 74→    if (sourceFilter !== 'all') params.sourceTool = sourceFilter;
 75→    return params;
 76→  }, [projectFilter, sourceFilter]);
 77→
 78→  const { data: sessions = [], isLoading: sessionsLoading, isError: sessionsError, refetch: refetchSessions } = useSessions(sessionParams);
 79→  const { data: insights = [], isLoading: insightsLoading } = useInsights();
 80→
 81→  const analyzedSessionIds = useMemo(
 82→    () => new Set(insights.map((i) => i.session_id)),
 83→    [insights]
 84→  );
 85→
 86→  const filteredSessions = useMemo(() => {
 87→    return sessions.filter((s) => {
 88→      if (characterFilter !== 'all' && s.session_character !== characterFilter) return false;
 89→      if (statusFilter === 'analyzed' && !analyzedSessionIds.has(s.id)) return false;
 90→      if (statusFilter === 'unanalyzed' && analyzedSessionIds.has(s.id)) return false;
 91→      if (search) {
 92→        const q = search.toLowerCase();
 93→        const title = getSessionTitle(s).toLowerCase();
 94→        if (!title.includes(q) && !s.project_name.toLowerCase().includes(q)) return false;
 95→      }
 96→      return true;
 97→    });
 98→  }, [sessions, characterFilter, statusFilter, search, analyzedSessionIds]);
 99→
100→  const groupedSessions = useMemo(() => {
101→    const groups: Record<string, Session[]> = {};
102→    for (const s of filteredSessions) {
103→      const group = getDateGroup(s.started_at);
104→      if (!groups[group]) groups[group] = [];
105→      groups[group].push(s);
106→    }
107→    return GROUP_ORDER.filter((g) => groups[g]).map((g) => ({ group: g, sessions: groups[g] }));
108→  }, [filteredSessions]);
109→
110→  const loading = sessionsLoading || projectsLoading || insightsLoading;
111→  const hasClientFilters = characterFilter !== 'all' || statusFilter !== 'all' || !!search;
112→  const hasAnyFilter = hasClientFilters || projectFilter !== 'all' || sourceFilter !== 'all';
113→
114→  const clearFilters = () => {
