133→          </p>
134→        )}
135→      </div>
136→
137→      {/* Filters */}
138→      <div className="space-y-2">
139→        <Input
140→          placeholder="Search sessions..."
141→          value={search}
142→          onChange={(e) => setSearch(e.target.value)}
143→          className="max-w-sm"
144→        />
145→        <div className="flex flex-wrap gap-2">
146→          <Select value={projectFilter} onValueChange={setProjectFilter}>
147→            <SelectTrigger className="w-[160px]">
148→              <SelectValue placeholder="All Projects" />
149→            </SelectTrigger>
150→            <SelectContent>
151→              <SelectItem value="all">All Projects</SelectItem>
152→              {projects.map((p) => (
153→                <SelectItem key={p.id} value={p.id}>
154→                  {p.name}
155→                </SelectItem>
156→              ))}
157→            </SelectContent>
158→          </Select>
159→
160→          <Select value={characterFilter} onValueChange={setCharacterFilter}>
161→            <SelectTrigger className="w-[160px]">
162→              <SelectValue placeholder="All Types" />
163→            </SelectTrigger>
164→            <SelectContent>
165→              <SelectItem value="all">All Types</SelectItem>
166→              {SESSION_CHARACTERS.map((c) => (
167→                <SelectItem key={c} value={c} className="capitalize">
