 1→import { useState, useEffect } from 'react';
 2→import {
 3→  Dialog,
 4→  DialogContent,
 5→  DialogDescription,
 6→  DialogFooter,
 7→  DialogHeader,
 8→  DialogTitle,
 9→} from '@/components/ui/dialog';
10→import { Button } from '@/components/ui/button';
11→import { Input } from '@/components/ui/input';
12→import { patchSession } from '@/lib/api';
13→import { toast } from 'sonner';
14→
15→interface RenameSessionDialogProps {
16→  open: boolean;
17→  onOpenChange: (open: boolean) => void;
18→  sessionId: string;
19→  currentTitle: string;
20→  onRenamed?: () => void;
21→}
22→
23→export function RenameSessionDialog({
24→  open,
25→  onOpenChange,
26→  sessionId,
27→  currentTitle,
28→  onRenamed,
29→}: RenameSessionDialogProps) {
30→  const [title, setTitle] = useState(currentTitle);
31→  const [saving, setSaving] = useState(false);
32→
33→  useEffect(() => {
34→    if (open) {
35→      setTitle(currentTitle);
36→    }
37→  }, [open, currentTitle]);
38→
39→  const handleSubmit = async (e: React.FormEvent) => {
40→    e.preventDefault();
41→    setSaving(true);
42→    try {
43→      await patchSession(sessionId, { customTitle: title });
44→      toast.success('Session renamed');
45→      onRenamed?.();
46→      onOpenChange(false);
47→    } catch (err) {
48→      toast.error(err instanceof Error ? err.message : 'Failed to rename session');
49→    } finally {
50→      setSaving(false);
51→    }
52→  };
53→
54→  return (
55→    <Dialog open={open} onOpenChange={onOpenChange}>
56→      <DialogContent className="sm:max-w-[425px]">
57→        <DialogHeader>
58→          <DialogTitle>Rename Session</DialogTitle>
59→          <DialogDescription>
60→            Give this session a custom name. Clear the field to revert to the auto-generated title.
61→          </DialogDescription>
62→        </DialogHeader>
63→        <form onSubmit={handleSubmit}>
64→          <div className="py-4">
65→            <Input
66→              value={title}
67→              onChange={(e) => setTitle(e.target.value)}
68→              placeholder="Enter a custom title..."
69→              autoFocus
70→            />
71→          </div>
72→          <DialogFooter>
73→            <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>
74→              Cancel
75→            </Button>
76→            <Button type="submit" disabled={saving}>
77→              {saving ? 'Saving...' : 'Save'}
78→            </Button>
79→          </DialogFooter>
80→        </form>
81→      </DialogContent>
82→    </Dialog>
83→  );
84→}
