 50→function getScoreColor(score: number): string {
 51→  if (score >= 80) return 'text-green-500';
 52→  if (score >= 60) return 'text-yellow-500';
 53→  if (score >= 40) return 'text-orange-500';
 54→  return 'text-red-500';
