 1→import { useInfiniteQuery } from '@tanstack/react-query';
 2→import { fetchMessages } from '@/lib/api';
 3→import type { Message } from '@/lib/types';
 4→
 5→const PAGE_SIZE = 50;
 6→
 7→export function useMessages(sessionId: string | undefined) {
 8→  return useInfiniteQuery({
 9→    queryKey: ['messages', sessionId],
10→    queryFn: ({ pageParam = 0 }: { pageParam: number }) =>
11→      fetchMessages(sessionId!, { limit: PAGE_SIZE, offset: pageParam }).then((r) => r.messages),
12→    initialPageParam: 0,
13→    getNextPageParam: (lastPage: Message[], _allPages: Message[][], lastPageParam: number) => {
14→      // If the page returned fewer messages than requested, we've reached the end.
15→      if (lastPage.length < PAGE_SIZE) return undefined;
16→      return lastPageParam + PAGE_SIZE;
17→    },
18→    enabled: !!sessionId,
19→  });
20→}
