196→                  {turn.originalMessage && (
197→                    <p className="text-xs text-muted-foreground italic line-clamp-2">
198→                      &ldquo;{turn.originalMessage}&rdquo;
199→                    </p>
200→                  )}
201→                  {turn.suggestedRewrite && (
202→                    <details className="text-xs">
203→                      <summary className="cursor-pointer text-muted-foreground hover:text-foreground">
204→                        Better prompt
205→                      </summary>
206→                      <p className="mt-1 bg-muted/50 rounded p-1.5">
207→                        {turn.suggestedRewrite}
208→                      </p>
209→                    </details>
210→                  )}
211→                </div>
212→              ))}
213→              {wastedTurns.length > 5 && (
214→                <p className="text-xs text-muted-foreground">
215→                  +{wastedTurns.length - 5} more wasted turns...
216→                </p>
217→              )}
218→            </div>
219→          </div>
220→        )}
221→
222→        {bullets.length > 0 && (
223→          <div className="space-y-2">
224→            <div className="flex items-center gap-1.5 text-sm font-medium">
225→              <Lightbulb className="h-3.5 w-3.5 text-yellow-500" />
226→              Tips
227→            </div>
228→            <ul className="list-disc list-inside space-y-1 text-sm text-muted-foreground">
229→              {bullets.map((tip, i) => (
230→                <li key={i}>{tip}</li>
231→              ))}
232→            </ul>
233→          </div>
234→        )}
235→      </CardContent>
236→    </Card>
237→  );
238→}
