 38→export function MessageBubble({ message, showHeader = true, nextToolResults = [], sourceTool }: MessageBubbleProps) {
 39→  const isUser = message.type === 'user';
 40→  const isSystem = message.type === 'system';
 41→  const hasContent = message.content?.trim();
 42→
 43→  const toolCalls = parseJsonField<ToolCall[]>(message.tool_calls, []);
 44→  const toolResults = parseJsonField<ToolResult[]>(message.tool_results, []);
 45→  const hasToolCalls = toolCalls.length > 0;
 46→
 47→  // Build result map from next message's tool_results (passed as prop) or own tool_results
 48→  const allResults = nextToolResults.length > 0 ? nextToolResults : toolResults;
 49→  const resultMap = useMemo(
 50→    () => new Map((allResults || []).map(r => [r.toolUseId, r])),
 51→    [allResults]
