 57→  // Detect and delegate agent coordination messages (task notifications, teammate messages).
 58→  // Memoized to match the resultMap pattern — parse cost is non-trivial for large tool outputs.
 59→  const agentMessage = useMemo(
 60→    () => (isUser && hasContent) ? parseAgentMessage(message.content) : null,
 61→    [isUser, hasContent, message.content]
 62→  );
 63→  if (agentMessage) {
 64→    return <AgentMessageBubble parsed={agentMessage} timestamp={message.timestamp} />;
