108→            <span className="text-xs text-muted-foreground">{format(new Date(message.timestamp), 'h:mm a')}</span>
109→          </div>
110→        )}
111→
112→        {message.thinking && <ThinkingBlock thinking={message.thinking} />}
113→
114→        {hasContent ? (
115→          <AssistantMarkdown content={message.content} codeStyle={codeStyle} />
116→        ) : null}
117→
118→        {hasToolCalls && (
119→          <div className="mt-2">
120→            {toolCalls.map((tc) => (
121→              <ToolPanel key={tc.id} toolCall={tc} result={resultMap.get(tc.id)} />
