 1→import type Database from 'better-sqlite3';
 2→import { SCHEMA_SQL, CURRENT_SCHEMA_VERSION } from './schema.js';
 3→
 4→/**
 5→ * Apply schema migrations to the database.
 6→ * Called once on startup before any reads or writes.
 7→ *
 8→ * Version 1: Initial schema (projects, sessions, messages, insights, usage_stats)
 9→ */
10→export function runMigrations(db: Database.Database): void {
11→  // Create schema_version table first if it doesn't exist.
12→  // This table is created inline (not via SCHEMA_SQL) so migrations can check it.
13→  db.exec(`
14→    CREATE TABLE IF NOT EXISTS schema_version (
15→      version    INTEGER PRIMARY KEY,
16→      applied_at TEXT NOT NULL DEFAULT (datetime('now'))
17→    );
18→  `);
19→
20→  const currentVersion = getCurrentVersion(db);
21→
22→  if (currentVersion < 1) {
23→    applyV1(db);
24→  }
25→
26→  // Future migrations: if (currentVersion < 2) { applyV2(db); }
27→}
28→
29→function getCurrentVersion(db: Database.Database): number {
30→  const row = db.prepare('SELECT MAX(version) as v FROM schema_version').get() as { v: number | null };
31→  return row.v ?? 0;
32→}
33→
34→function applyV1(db: Database.Database): void {
35→  db.exec(SCHEMA_SQL);
36→  db.prepare('INSERT OR IGNORE INTO schema_version (version) VALUES (?)').run(CURRENT_SCHEMA_VERSION);
37→}
