 12→// ─── Agent message types ──────────────────────────────────────────────────────
 13→
 14→export interface ParsedTaskNotification {
 15→  kind: 'task-notification';
 16→  taskId?: string;
 17→  status?: string;
 18→  summary?: string;
 19→  result?: string;
 20→  usage?: { tokens?: string; duration?: string; toolUses?: string };
 21→  transcriptPath?: string;
 22→}
 23→
 24→export interface ParsedTeammateMessage {
 25→  kind: 'teammate-message';
 26→  teammateId?: string;
 27→  color?: string;
 28→  from?: string;
 29→  type?: string;
 30→  summary?: string;
 31→  content?: string;
 32→  rawContent: string;
 33→}
 34→
 35→export type ParsedAgentMessage = ParsedTaskNotification | ParsedTeammateMessage;
 36→
 37→/**
 38→ * Fast check: does this content contain agent message XML tags?
 39→ * Uses string.includes() for the hot path — no regex overhead for 99% of messages.
 40→ */
 41→export function isAgentMessage(content: string): boolean {
 42→  return content.includes('<task-notification>') || content.includes('<teammate-message');
 43→}
 44→
 45→/**
 46→ * Parse agent message content into a typed struct.
 47→ * Returns null if content doesn't match any known agent message pattern.
 48→ */
 49→export function parseAgentMessage(content: string): ParsedAgentMessage | null {
 50→  if (content.includes('<task-notification>')) {
 51→    return parseTaskNotification(content);
 52→  }
 53→  if (content.includes('<teammate-message')) {
 54→    return parseTeammateMessage(content);
 55→  }
 56→  return null;
 57→}
 58→
 59→/**
 60→ * Extract the text content of an XML-like tag from a string.
 61→ * Uses a lazy quantifier (*?) so it matches up to the FIRST closing tag.
 62→ * This means nested same-name tags would cause truncation — acceptable
 63→ * because Claude Code's agent message format does not produce nested
 64→ * same-name tags, and the same pattern is used by preprocessUserContent.
 65→ */
 66→function extractTag(content: string, tag: string): string | undefined {
 67→  const re = new RegExp(`<${tag}>([\\s\\S]*?)<\\/${tag}>`);
 68→  const match = re.exec(content);
 69→  return match ? match[1].trim() : undefined;
 70→}
 71→
 72→function parseTaskNotification(content: string): ParsedTaskNotification {
 73→  const taskId = extractTag(content, 'task_id');
 74→  const status = extractTag(content, 'status');
 75→  const summary = extractTag(content, 'summary');
 76→  const result = extractTag(content, 'result');
 77→
 78→  // Parse usage block for tokens, duration, tool_uses lines
 79→  const usageBlock = extractTag(content, 'usage');
 80→  let usage: ParsedTaskNotification['usage'];
 81→  if (usageBlock) {
 82→    const tokensMatch = /total_tokens:\s*(\S+)/.exec(usageBlock);
 83→    const durationMatch = /duration:\s*(\S+)/.exec(usageBlock);
 84→    const toolUsesMatch = /tool_uses:\s*(\S+)/.exec(usageBlock);
 85→    usage = {
 86→      tokens: tokensMatch ? tokensMatch[1] : undefined,
 87→      duration: durationMatch ? durationMatch[1] : undefined,
 88→      toolUses: toolUsesMatch ? toolUsesMatch[1] : undefined,
 89→    };
 90→  }
 91→
 92→  // Transcript path: text AFTER </task-notification>, look for a path starting with /
 93→  const afterTag = content.split('</task-notification>')[1] ?? '';
 94→  const pathMatch = /^\s*(\/[^\s]+)/m.exec(afterTag);
 95→  const transcriptPath = pathMatch ? pathMatch[1] : undefined;
 96→
 97→  return { kind: 'task-notification', taskId, status, summary, result, usage, transcriptPath };
 98→}
 99→
100→function parseTeammateMessage(content: string): ParsedTeammateMessage {
101→  // Extract attributes from opening tag: <teammate-message teammate_id="..." color="...">
102→  const tagMatch = /<teammate-message([^>]*)>/.exec(content);
103→  const attrs = tagMatch ? tagMatch[1] : '';
104→
105→  const teammateIdMatch = /teammate_id="([^"]*)"/.exec(attrs);
106→  const colorMatch = /color="([^"]*)"/.exec(attrs);
107→
108→  const teammateId = teammateIdMatch ? teammateIdMatch[1] : undefined;
109→  const color = colorMatch ? colorMatch[1] : undefined;
110→
111→  // Inner content between > and </teammate-message>
112→  const innerMatch = /<teammate-message[^>]*>([\s\S]*?)<\/teammate-message>/.exec(content);
113→  const rawContent = innerMatch ? innerMatch[1].trim() : content;
114→
115→  // Try to parse as JSON for type, from, summary, content fields
116→  try {
117→    const parsed = JSON.parse(rawContent) as Record<string, unknown>;
118→    return {
119→      kind: 'teammate-message',
120→      teammateId,
121→      color,
122→      from: typeof parsed.from === 'string' ? parsed.from : undefined,
123→      type: typeof parsed.type === 'string' ? parsed.type : undefined,
124→      summary: typeof parsed.summary === 'string' ? parsed.summary : undefined,
125→      content: typeof parsed.content === 'string' ? parsed.content : undefined,
126→      rawContent,
127→    };
128→  } catch {
129→    return { kind: 'teammate-message', teammateId, color, rawContent };
130→  }
131→}
132→
133→// ─── User content preprocessing ───────────────────────────────────────────────
134→
135→/**
136→ * Preprocess user message content to handle slash command XML tags from Claude Code sessions.
137→ * - <command-name>/foo</command-name> → `/foo`
138→ * - <command-message>...</command-message> → stripped
139→ * - <command-args>...</command-args> → stripped
140→ * - <local-command-stdout>text</local-command-stdout> → code block output
141→ */
142→export function preprocessUserContent(content: string): string {
143→  let result = content;
144→
145→  // Strip <command-message>...</command-message>
146→  result = result.replace(/<command-message>[\s\S]*?<\/command-message>/g, '');
147→
148→  // Strip <command-args>...</command-args>
149→  result = result.replace(/<command-args>[\s\S]*?<\/command-args>/g, '');
150→
151→  // Replace <command-name>/foo</command-name> with `/foo`
152→  result = result.replace(/<command-name>(\/[^<]*)<\/command-name>/g, '`$1`');
153→
154→  // Replace <local-command-stdout>text</local-command-stdout> with a code block
155→  result = result.replace(
156→    /<local-command-stdout>([\s\S]*?)<\/local-command-stdout>/g,
157→    (_, stdout) => {
158→      const trimmed = stdout.trim();
159→      if (!trimmed) return '';
160→      return `\n\`\`\`\n${trimmed}\n\`\`\``;
161→    }
162→  );
163→
164→  // Clean up excess blank lines from stripping
165→  result = result.replace(/\n{3,}/g, '\n\n').trim();
166→
167→  return result;
168→}
