 1→import { useEffect, useRef } from 'react';
 2→import { BrowserRouter, Routes, Route, Navigate, useLocation } from 'react-router';
 3→import { capturePageView, captureDashboardLoaded } from '@/lib/telemetry';
 4→import { Layout } from '@/components/layout/Layout';
 5→import DashboardPage from '@/pages/DashboardPage';
 6→import SessionsPage from '@/pages/SessionsPage';
 7→import SessionDetailPage from '@/pages/SessionDetailPage';
 8→import InsightsPage from '@/pages/InsightsPage';
 9→import AnalyticsPage from '@/pages/AnalyticsPage';
10→import SettingsPage from '@/pages/SettingsPage';
11→import ExportPage from '@/pages/ExportPage';
12→import JournalPage from '@/pages/JournalPage';
13→
14→const ROUTE_TITLES: Record<string, string> = {
15→  '/dashboard': 'Dashboard',
16→  '/sessions': 'Sessions',
17→  '/insights': 'Insights',
18→  '/analytics': 'Analytics',
19→  '/export': 'Export',
20→  '/journal': 'Journal',
21→  '/settings': 'Settings',
22→};
23→
24→function RouteEffects() {
25→  const { pathname } = useLocation();
26→  const navStartRef = useRef<number>(Date.now());
27→
28→  // Scroll to top on route change
29→  useEffect(() => {
30→    window.scrollTo(0, 0);
31→  }, [pathname]);
32→
33→  // Update document.title per route, track page views, and capture dashboard_loaded
34→  useEffect(() => {
35→    const segment = '/' + pathname.split('/')[1];
36→    const page = ROUTE_TITLES[segment];
37→    document.title = page ? `${page} — Code Insights` : 'Code Insights';
38→
39→    // Track page view on every route change
40→    capturePageView(pathname);
41→
42→    // Capture dashboard_loaded with time since navigation started
43→    if (page) {
44→      const loadTimeMs = Date.now() - navStartRef.current;
45→      captureDashboardLoaded(page.toLowerCase(), loadTimeMs);
46→    }
47→    // Reset nav start for next navigation
48→    navStartRef.current = Date.now();
49→  }, [pathname]);
50→
51→  return null;
52→}
53→
54→export default function App() {
55→  return (
56→    <BrowserRouter>
57→      <RouteEffects />
58→      <Routes>
59→        <Route element={<Layout />}>
60→          <Route index element={<Navigate to="/dashboard" replace />} />
61→          <Route path="/dashboard" element={<DashboardPage />} />
62→          <Route path="/sessions" element={<SessionsPage />} />
63→          <Route path="/sessions/:id" element={<SessionDetailPage />} />
64→          <Route path="/insights" element={<InsightsPage />} />
65→          <Route path="/analytics" element={<AnalyticsPage />} />
66→          <Route path="/settings" element={<SettingsPage />} />
67→          <Route path="/export" element={<ExportPage />} />
68→          <Route path="/journal" element={<JournalPage />} />
69→          <Route path="*" element={<Navigate to="/dashboard" replace />} />
70→        </Route>
71→      </Routes>
72→    </BrowserRouter>
73→  );
74→}
