  8→import type { ParsedAgentMessage, ParsedTaskNotification, ParsedTeammateMessage } from './preprocess';
  9→
 10→interface AgentMessageBubbleProps {
 11→  parsed: ParsedAgentMessage;
 12→  timestamp: string;
 13→}
 14→
 15→export function AgentMessageBubble({ parsed, timestamp }: AgentMessageBubbleProps) {
 16→  if (parsed.kind === 'task-notification') {
 17→    return <TaskNotificationCard parsed={parsed} timestamp={timestamp} />;
 18→  }
 19→  return <TeammateMessageCard parsed={parsed} timestamp={timestamp} />;
