 22→// ─── TaskNotificationCard ─────────────────────────────────────────────────────
 23→
 24→function getStatusBadgeClass(status?: string): string {
 25→  if (!status) return 'bg-gray-500/10 text-gray-500 border-gray-500/20';
 26→  const lower = status.toLowerCase();
 27→  if (lower === 'completed' || lower === 'success') {
 28→    return 'bg-green-500/10 text-green-600 border-green-500/20';
 29→  }
 30→  if (lower === 'failed' || lower === 'error') {
 31→    return 'bg-red-500/10 text-red-600 border-red-500/20';
 32→  }
 33→  return 'bg-gray-500/10 text-gray-500 border-gray-500/20';
 34→}
 35→
 36→function TaskNotificationCard({
 37→  parsed,
 38→  timestamp,
 39→}: {
 40→  parsed: ParsedTaskNotification;
 41→  timestamp: string;
 42→}) {
 43→  const [expanded, setExpanded] = useState(false);
 44→  const hasResult = Boolean(parsed.result);
 45→  const hasUsage = Boolean(parsed.usage?.tokens || parsed.usage?.duration || parsed.usage?.toolUses);
 46→
 47→  const usageParts: string[] = [];
 48→  if (parsed.usage?.tokens) usageParts.push(`${parsed.usage.tokens} tokens`);
 49→  if (parsed.usage?.duration) usageParts.push(parsed.usage.duration);
 50→  if (parsed.usage?.toolUses) usageParts.push(`${parsed.usage.toolUses} tool uses`);
 51→
 52→  return (
 53→    <div className="border-l-4 border-amber-500/40 bg-amber-500/5 rounded-lg p-3 mx-4 my-2">
 54→      {/* Header row */}
 55→      <div className="flex items-center gap-2">
 56→        <BellRing className="h-4 w-4 text-amber-500 shrink-0" />
 57→        <span className="text-sm font-medium flex-1 min-w-0 truncate">
 58→          {parsed.summary ?? 'Task notification'}
 59→        </span>
 60→        {parsed.status && (
 61→          <span
 62→            className={cn(
 63→              'shrink-0 text-xs px-1.5 py-0.5 rounded border',
 64→              getStatusBadgeClass(parsed.status)
 65→            )}
 66→          >
 67→            {parsed.status}
 68→          </span>
 69→        )}
 70→        <span className="shrink-0 text-xs text-muted-foreground">
 71→          {format(new Date(timestamp), 'h:mm a')}
 72→        </span>
 73→      </div>
 74→
 75→      {/* Collapsible result section */}
 76→      {hasResult && (
 77→        <div className="mt-2">
 78→          <button
 79→            onClick={() => setExpanded((v) => !v)}
 80→            aria-expanded={expanded}
 81→            className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors"
 82→          >
 83→            {expanded ? (
 84→              <ChevronDown className="h-3 w-3" />
 85→            ) : (
 86→              <ChevronRight className="h-3 w-3" />
 87→            )}
 88→            {expanded ? 'Hide result' : 'Show result'}
 89→          </button>
 90→          {expanded && parsed.result && (
 91→            <div className="mt-2">
 92→              <AssistantMarkdown content={parsed.result} codeStyle={oneDark} />
 93→            </div>
 94→          )}
 95→        </div>
 96→      )}
 97→
 98→      {/* Usage footer */}
 99→      {hasUsage && (
100→        <div className="mt-2 text-xs text-muted-foreground">
101→          {usageParts.join(' · ')}
102→        </div>
103→      )}
104→    </div>
105→  );
106→}
107→
108→// ─── TeammateMessageCard ──────────────────────────────────────────────────────
109→
110→function TeammateMessageCard({
111→  parsed,
112→  timestamp,
113→}: {
114→  parsed: ParsedTeammateMessage;
115→  timestamp: string;
116→}) {
117→  // Resolve color tokens from the color attribute, fallback to gray
118→  const colors =
119→    parsed.color && parsed.color in TEAMMATE_BORDER_COLORS
120→      ? TEAMMATE_BORDER_COLORS[parsed.color]
121→      : TEAMMATE_DEFAULT_COLORS;
122→
123→  const displayName = parsed.from ?? parsed.teammateId ?? 'Agent';
124→
125→  return (
126→    <div className={cn('border-l-4 rounded-lg p-3 mx-4 my-2', colors.border, colors.bg)}>
127→      {/* Header row */}
128→      <div className="flex items-center gap-2">
129→        <MessageSquare className={cn('h-4 w-4 shrink-0', colors.text)} />
130→        <span className="text-sm font-medium flex-1 min-w-0 truncate">{displayName}</span>
131→        {parsed.type && (
132→          <span className="shrink-0 text-xs px-1.5 py-0.5 rounded border bg-muted/50 text-muted-foreground border-border">
133→            {parsed.type}
134→          </span>
135→        )}
136→        <span className="shrink-0 text-xs text-muted-foreground">
137→          {format(new Date(timestamp), 'h:mm a')}
138→        </span>
139→      </div>
140→
141→      {/* Message body — prefer summary, then content, then raw */}
142→      {(parsed.summary ?? parsed.content ?? parsed.rawContent) && (
143→        <div className="mt-1.5 text-sm text-foreground/80 whitespace-pre-wrap break-words">
144→          {parsed.summary ?? parsed.content ?? parsed.rawContent}
145→        </div>
146→      )}
147→    </div>
148→  );
149→}
