 12→function getFileName(filePath: string): string {
 13→  return filePath.split('/').pop() || filePath;
 14→}
 15→
 16→function detectLanguage(filePath: string): string | null {
 17→  const ext = filePath.split('.').pop()?.toLowerCase();
 18→  const map: Record<string, string> = {
 19→    ts: 'TypeScript', tsx: 'TypeScript', js: 'JavaScript', jsx: 'JavaScript',
 20→    py: 'Python', rs: 'Rust', go: 'Go', md: 'Markdown', json: 'JSON',
 21→    css: 'CSS', html: 'HTML', yaml: 'YAML', yml: 'YAML', sh: 'Shell',
 22→    sql: 'SQL', toml: 'TOML',
 23→  };
 24→  return ext ? map[ext] || null : null;
 25→}
 26→
 27→export function FileToolPanel({ toolCall, result }: FileToolPanelProps) {
 28→  const input = parseToolInput(toolCall.input);
 29→  const filePath = (input.file_path as string) || '';
 30→  const fileName = getFileName(filePath);
 31→  const lang = detectLanguage(filePath);
