 40→  const oldString = isEdit ? (input.old_string as string) || '' : '';
 41→  const newString = isEdit ? (input.new_string as string) || '' : '';
 42→
 43→  const resultText = result?.output || '';
 44→  const PREVIEW_LINES = 8;
 45→  const { hasMore, previewText, resultLines, showFull, toggle } = usePreviewText(resultText, PREVIEW_LINES);
 46→
 47→  return (
 48→    <div className="my-2 rounded-lg border border-border overflow-hidden">
 49→      <ToolPanelHeader
 50→        className="bg-muted/60 border-border"
 51→        icon={<Icon className="h-3.5 w-3.5 text-blue-500 shrink-0" />}
 52→        title={label}
 53→        meta={(
 54→          <code className="text-xs text-muted-foreground font-mono truncate" title={filePath}>
 55→            {fileName || 'file'}
 56→          </code>
 57→        )}
 58→        rightContent={lang ? <span className="text-[10px] text-muted-foreground/60">{lang}</span> : null}
 59→      />
 60→
 61→      {isEdit && (oldString || newString) && (
 62→        <div className="text-xs font-mono overflow-x-auto">
