 66→              <span className="text-red-700 dark:text-red-400 whitespace-pre-wrap">{oldString.length > 500 ? oldString.slice(0, 500) + '...' : oldString}</span>
 67→            </div>
 68→          )}
 69→          {newString && (
 70→            <div className="bg-green-500/8 px-3 py-1.5">
 71→              <span className="text-green-500/60 select-none mr-2">+</span>
