 25→interface AnalyzeDropdownProps {
 26→  session: Session;
 27→  hasExistingInsights?: boolean;
 28→  insightCount?: number;
 29→  hasExistingPromptQuality?: boolean;
 30→}
 31→
 32→export function AnalyzeDropdown({
 33→  session,
 34→  hasExistingInsights,
 35→  insightCount,
 36→  hasExistingPromptQuality,
 37→}: AnalyzeDropdownProps) {
 38→  const [confirmSessionOpen, setConfirmSessionOpen] = useState(false);
 39→  const [confirmPromptOpen, setConfirmPromptOpen] = useState(false);
 40→  const { state: analysisState, startAnalysis, cancelAnalysis } = useAnalysis();
 41→  const { data: llmConfig } = useLlmConfig();
 42→
 43→  const configured = !!(llmConfig?.provider && llmConfig?.model);
 44→
 45→  const isAnalyzingThisSession =
 46→    analysisState.status === 'analyzing' && analysisState.sessionId === session.id;
 47→  const isAnalyzingOther =
 48→    analysisState.status === 'analyzing' && analysisState.sessionId !== session.id;
 49→  const isCompleteForSession =
 50→    analysisState.status === 'complete' &&
 51→    analysisState.sessionId === session.id &&
 52→    analysisState.type === 'session';
 53→
 54→  const handleSessionAnalyze = () => {
 55→    startAnalysis(session, 'session');
 56→  };
 57→
 58→  const handlePromptAnalyze = () => {
 59→    startAnalysis(session, 'prompt_quality');
 60→  };
 61→
 62→  const handleSessionClick = () => {
 63→    if (hasExistingInsights && !isCompleteForSession) {
 64→      setConfirmSessionOpen(true);
 65→    } else {
 66→      handleSessionAnalyze();
 67→    }
 68→  };
 69→
 70→  const handlePromptClick = () => {
 71→    const isCompleteForPrompt =
 72→      analysisState.status === 'complete' &&
 73→      analysisState.sessionId === session.id &&
 74→      analysisState.type === 'prompt_quality';
 75→
 76→    if (hasExistingPromptQuality && !isCompleteForPrompt) {
 77→      setConfirmPromptOpen(true);
 78→    } else {
 79→      handlePromptAnalyze();
 80→    }
 81→  };
 82→
 83→  if (!configured) {
 84→    return (
 85→      <Link
 86→        to="/settings"
 87→        className="text-xs text-muted-foreground underline hover:text-foreground"
 88→      >
 89→        Configure AI in Settings
 90→      </Link>
 91→    );
 92→  }
 93→
 94→  if (isAnalyzingThisSession) {
 95→    return (
 96→      <div className="flex items-center gap-1.5">
 97→        <Button disabled variant="outline" size="sm" className="h-8 gap-2">
 98→          <Loader2 className="h-3.5 w-3.5 animate-spin" />
 99→          <span className="hidden sm:inline">
100→            {analysisState.progress?.message || 'Analyzing...'}
101→          </span>
102→          <span className="sm:hidden">Analyzing...</span>
103→        </Button>
104→        <Button
105→          variant="ghost"
106→          size="sm"
107→          className="h-8 gap-1 text-muted-foreground hover:text-foreground"
108→          onClick={cancelAnalysis}
109→        >
110→          <X className="h-3.5 w-3.5" />
111→          <span className="sr-only sm:not-sr-only">Cancel</span>
112→        </Button>
113→      </div>
114→    );
115→  }
116→
117→  if (isAnalyzingOther) {
118→    return (
119→      <div className="flex items-center gap-1.5">
120→        <Button disabled variant="outline" size="sm" className="h-8 gap-2">
121→          <Loader2 className="h-3.5 w-3.5 animate-spin" />
122→          Analysis in progress...
123→        </Button>
124→        <span className="text-xs text-muted-foreground">
125→          Waiting for &quot;{analysisState.sessionTitle}&quot;
126→        </span>
127→      </div>
128→    );
129→  }
130→
131→  const showPromptOption = session.user_message_count >= 2;
132→
133→  return (
134→    <>
135→      <DropdownMenu>
136→        <DropdownMenuTrigger asChild>
137→          <Button variant="outline" size="sm" className="h-8 gap-1.5">
138→            <Sparkles className="h-3.5 w-3.5" />
139→            Analyze
140→            <ChevronDown className="h-3 w-3 opacity-50" />
141→          </Button>
142→        </DropdownMenuTrigger>
143→        <DropdownMenuContent align="end">
144→          <DropdownMenuItem onClick={handleSessionClick}>
145→            <Sparkles className="h-4 w-4" />
146→            {hasExistingInsights ? 'Re-analyze Session' : 'Analyze Session'}
147→          </DropdownMenuItem>
148→          {showPromptOption && (
149→            <DropdownMenuItem onClick={handlePromptClick}>
150→              <Target className="h-4 w-4" />
151→              {hasExistingPromptQuality ? 'Re-analyze Prompt Quality' : 'Analyze Prompt Quality'}
152→            </DropdownMenuItem>
153→          )}
154→        </DropdownMenuContent>
155→      </DropdownMenu>
156→
157→      <AlertDialog open={confirmSessionOpen} onOpenChange={setConfirmSessionOpen}>
158→        <AlertDialogContent>
159→          <AlertDialogHeader>
160→            <AlertDialogTitle>Re-analyze this session?</AlertDialogTitle>
161→            <AlertDialogDescription>
162→              This will replace {insightCount ?? 0} existing insight{(insightCount ?? 0) !== 1 ? 's' : ''} with new ones.
163→              This uses LLM tokens and cannot be undone.
164→            </AlertDialogDescription>
165→          </AlertDialogHeader>
166→          <AlertDialogFooter>
167→            <AlertDialogCancel>Cancel</AlertDialogCancel>
168→            <AlertDialogAction onClick={handleSessionAnalyze}>Re-analyze</AlertDialogAction>
169→          </AlertDialogFooter>
170→        </AlertDialogContent>
171→      </AlertDialog>
172→
173→      <AlertDialog open={confirmPromptOpen} onOpenChange={setConfirmPromptOpen}>
174→        <AlertDialogContent>
175→          <AlertDialogHeader>
176→            <AlertDialogTitle>Re-analyze prompt quality?</AlertDialogTitle>
177→            <AlertDialogDescription>
178→              This will replace the current prompt quality score with a new one.
179→              This uses LLM tokens and cannot be undone.
180→            </AlertDialogDescription>
181→          </AlertDialogHeader>
182→          <AlertDialogFooter>
183→            <AlertDialogCancel>Cancel</AlertDialogCancel>
184→            <AlertDialogAction onClick={handlePromptAnalyze}>Re-analyze</AlertDialogAction>
185→          </AlertDialogFooter>
186→        </AlertDialogContent>
187→      </AlertDialog>
188→    </>
189→  );
190→}
