 1→import { Hono } from 'hono';
 2→import { getDb } from '@code-insights/cli/db/client';
 3→import { parseIntParam } from '../utils.js';
 4→
 5→const app = new Hono();
 6→
 7→app.get('/', (c) => {
 8→  const db = getDb();
 9→  const { projectId, sourceTool, limit, offset } = c.req.query();
10→
11→  const conditions: string[] = [];
12→  const params: (string | number)[] = [];
13→
14→  if (projectId) {
15→    conditions.push('project_id = ?');
16→    params.push(projectId);
17→  }
18→  if (sourceTool) {
19→    conditions.push('source_tool = ?');
20→    params.push(sourceTool);
21→  }
22→
23→  const where = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
24→  const sessions = db.prepare(`
25→    SELECT id, project_id, project_name, project_path, git_remote_url,
26→           summary, custom_title, generated_title, title_source, session_character,
27→           started_at, ended_at, message_count, user_message_count,
28→           assistant_message_count, tool_call_count, git_branch,
29→           claude_version, source_tool, device_id, device_hostname,
30→           device_platform, synced_at, total_input_tokens, total_output_tokens,
31→           cache_creation_tokens, cache_read_tokens, estimated_cost_usd,
32→           models_used, primary_model, usage_source
33→    FROM sessions
34→    ${where}
35→    ORDER BY started_at DESC
36→    LIMIT ? OFFSET ?
37→  `).all(...params, parseIntParam(limit, 50), parseIntParam(offset, 0));
38→
39→  return c.json({ sessions });
40→});
41→
42→app.get('/:id', (c) => {
43→  const db = getDb();
44→  const session = db.prepare(`
45→    SELECT id, project_id, project_name, project_path, git_remote_url,
46→           summary, custom_title, generated_title, title_source, session_character,
47→           started_at, ended_at, message_count, user_message_count,
48→           assistant_message_count, tool_call_count, git_branch,
49→           claude_version, source_tool, device_id, device_hostname,
50→           device_platform, synced_at, total_input_tokens, total_output_tokens,
51→           cache_creation_tokens, cache_read_tokens, estimated_cost_usd,
52→           models_used, primary_model, usage_source
53→    FROM sessions WHERE id = ?
54→  `).get(c.req.param('id'));
55→  if (!session) return c.json({ error: 'Not found' }, 404);
56→  return c.json({ session });
57→});
58→
59→app.patch('/:id', async (c) => {
60→  const db = getDb();
61→  const body = await c.req.json<{ customTitle?: string }>();
62→  const { customTitle } = body;
63→  if (customTitle === undefined) {
64→    return c.json({ error: 'customTitle is required' }, 400);
65→  }
66→  const result = db.prepare('UPDATE sessions SET custom_title = ? WHERE id = ?').run(
67→    customTitle || null,
68→    c.req.param('id'),
69→  );
70→  if (result.changes === 0) return c.json({ error: 'Not found' }, 404);
71→  return c.json({ ok: true });
72→});
73→
74→export default app;
