 45→function getDateGroup(dateStr: string): string {
 46→  const date = new Date(dateStr);
 47→  const now = new Date();
 48→  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
 49→  const yesterday = new Date(today);
 50→  yesterday.setDate(yesterday.getDate() - 1);
 51→  const thisWeekStart = new Date(today);
 52→  thisWeekStart.setDate(thisWeekStart.getDate() - 7);
 53→
 54→  const sessionDay = new Date(date.getFullYear(), date.getMonth(), date.getDate());
 55→
 56→  if (sessionDay.getTime() === today.getTime()) return 'Today';
 57→  if (sessionDay.getTime() === yesterday.getTime()) return 'Yesterday';
 58→  if (sessionDay >= thisWeekStart) return 'This Week';
 59→  return 'Earlier';
 60→}
 61→
 62→const GROUP_ORDER = ['Today', 'Yesterday', 'This Week', 'Earlier'];
 63→
 64→/** Short type abbreviations for compact insight count display */
 65→const INSIGHT_TYPE_ABBREV: Record<string, string> = {
 66→  summary: 'S',
 67→  decision: 'D',
 68→  learning: 'L',
 69→  technique: 'L',
 70→  prompt_quality: 'PQ',
 71→};
 72→
 73→function getCostColor(cost: number): string {
 74→  if (cost < 0.10) return 'bg-green-500/10 text-green-600 border-green-500/20';
 75→  if (cost < 0.50) return 'bg-yellow-500/10 text-yellow-600 border-yellow-500/20';
 76→  return 'bg-red-500/10 text-red-600 border-red-500/20';
 77→}
