304→function InsightCountBadge({ counts }: { counts: Record<string, number> | undefined }) {
305→  if (!counts) {
306→    return (
307→      <span className="flex items-center gap-1 text-xs text-muted-foreground">
308→        <Sparkles className="h-3 w-3" />
309→        Not analyzed
310→      </span>
311→    );
312→  }
313→
314→  const total = Object.values(counts).reduce((a, b) => a + b, 0);
315→  // Build compact breakdown string like "2L 1D"
316→  const breakdown = Object.entries(counts)
317→    .filter(([type]) => type !== 'summary') // Don't show summary in breakdown
318→    .sort(([, a], [, b]) => b - a)
319→    .map(([type, count]) => `${count}${INSIGHT_TYPE_ABBREV[type] || type[0].toUpperCase()}`)
320→    .join(' ');
321→
322→  return (
323→    <span className="flex items-center gap-1 text-xs text-muted-foreground">
324→      <Sparkles className="h-3 w-3 text-purple-500" />
325→      {total} insight{total !== 1 ? 's' : ''}
326→      {breakdown && <span className="text-muted-foreground/70">({breakdown})</span>}
327→    </span>
328→  );
329→}
