 29→  return (
 30→    <div className="space-y-0.5">
 31→      <span className="text-[11px] font-medium uppercase tracking-wider text-muted-foreground/70">{label}</span>
 32→      <p className={prominent ? 'text-sm font-medium text-foreground' : 'text-sm text-muted-foreground'}>{children}</p>
 33→    </div>
 34→  );
 35→}
 36→
 37→export function formatAlternatives(alternatives: InsightMetadata['alternatives']): string {
 38→  if (!alternatives || alternatives.length === 0) return '';
 39→  return alternatives.map(a => {
 40→    if (typeof a === 'string') return a;
 41→    return a.rejected_because ? `${a.option} (rejected: ${a.rejected_because})` : a.option;
 42→  }).join('; ');
 43→}
 44→
 45→// --- Type-specific content components ---
 46→
 47→export function DecisionContent({ metadata }: { metadata: InsightMetadata }) {
 48→  const hasStructured = metadata.situation || metadata.choice || metadata.reasoning;
 49→  if (!hasStructured) return null;
 50→
 51→  return (
 52→    <div className="space-y-2.5">
 53→      {metadata.situation && <MetadataSection label="Situation">{metadata.situation}</MetadataSection>}
 54→      {metadata.choice && <MetadataSection label="Choice" prominent>{metadata.choice}</MetadataSection>}
 55→      {metadata.reasoning && <MetadataSection label="Reasoning">{metadata.reasoning}</MetadataSection>}
 56→      {metadata.alternatives && metadata.alternatives.length > 0 && (
 57→        <MetadataSection label="Alternatives Considered">{formatAlternatives(metadata.alternatives)}</MetadataSection>
 58→      )}
 59→      {metadata.trade_offs && <MetadataSection label="Trade-offs">{metadata.trade_offs}</MetadataSection>}
 60→      {metadata.revisit_when && metadata.revisit_when !== 'N/A' && (
 61→        <MetadataSection label="Revisit When">{metadata.revisit_when}</MetadataSection>
 62→      )}
 63→      {metadata.evidence && metadata.evidence.length > 0 && (
 64→        <MetadataSection label="Evidence">{metadata.evidence.join(', ')}</MetadataSection>
 65→      )}
 66→    </div>
 67→  );
 68→}
 69→
 70→export function LearningContent({ metadata }: { metadata: InsightMetadata }) {
 71→  const hasStructured = metadata.symptom || metadata.root_cause || metadata.takeaway;
 72→  if (!hasStructured) return null;
 73→
 74→  return (
 75→    <div className="space-y-2.5">
 76→      {metadata.symptom && <MetadataSection label="What Happened">{metadata.symptom}</MetadataSection>}
 77→      {metadata.root_cause && <MetadataSection label="Why">{metadata.root_cause}</MetadataSection>}
 78→      {metadata.takeaway && <MetadataSection label="Takeaway" prominent>{metadata.takeaway}</MetadataSection>}
 79→      {metadata.applies_when && <MetadataSection label="Applies When">{metadata.applies_when}</MetadataSection>}
 80→    </div>
 81→  );
 82→}
 83→
 84→export function SummaryContent({ metadata, bullets }: { metadata: InsightMetadata; bullets: string[] }) {
 85→  return (
 86→    <div className="space-y-2">
 87→      {metadata.outcome && (
 88→        <div>
 89→          <OutcomeBadge outcome={metadata.outcome} />
 90→        </div>
 91→      )}
 92→      {bullets.length > 0 && (
 93→        <ul className="list-disc list-inside space-y-1 text-sm text-muted-foreground">
 94→          {bullets.map((bullet, i) => (
 95→            <li key={i} className="line-clamp-1">{bullet}</li>
 96→          ))}
 97→        </ul>
 98→      )}
 99→    </div>
100→  );
101→}
102→
103→export function renderTypeContent(type: InsightType, metadata: InsightMetadata, bullets: string[]) {
104→  switch (type) {
105→    case 'decision':
106→      return <DecisionContent metadata={metadata} />;
107→    case 'learning':
108→    case 'technique':
109→      return <LearningContent metadata={metadata} />;
110→    case 'summary':
111→      return <SummaryContent metadata={metadata} bullets={bullets} />;
112→    default:
113→      return null;
114→  }
