154→            </div>
155→            <div className="space-y-1.5">
156→              {sessionTraits.map((t, i) => (
157→                <div key={i} className="text-sm rounded-md border p-2 space-y-1">
158→                  <div className="flex items-center justify-between">
159→                    <span className="font-medium">{TRAIT_LABELS[t.trait] || t.trait}</span>
160→                    <Badge variant="outline" className={`text-xs ${
161→                      t.trait === 'good_structure'
