312→  }
313→
314→  const total = Object.values(counts).reduce((a, b) => a + b, 0);
315→  // Build compact breakdown string like "2L 1D"
316→  const breakdown = Object.entries(counts)
317→    .filter(([type]) => type !== 'summary') // Don't show summary in breakdown
318→    .sort(([, a], [, b]) => b - a)
319→    .map(([type, count]) => `${count}${INSIGHT_TYPE_ABBREV[type] || type[0].toUpperCase()}`)
320→    .join(' ');
