 19→/**
 20→ * Determines if a date separator should be shown before a message.
 21→ * Shows a separator at the start and whenever the hour changes.
 22→ */
 23→function shouldShowDateSeparator(messages: Message[], index: number): boolean {
 24→  if (index === 0) return true;
 25→  const prev = messages[index - 1];
 26→  const curr = messages[index];
 27→  const prevHour = new Date(prev.timestamp);
 28→  prevHour.setMinutes(0, 0, 0);
 29→  const currHour = new Date(curr.timestamp);
 30→  currHour.setMinutes(0, 0, 0);
 31→  return prevHour.getTime() !== currHour.getTime();
 32→}
 33→
 34→export function ChatConversation({
 35→  messages, loading, loadingMore, hasMore, onLoadMore, error, sourceTool,
 36→}: ChatConversationProps) {
 37→  if (loading) {
 38→    return (
 39→      <div className="space-y-4 p-4">
 40→        {[...Array(5)].map((_, i) => (
 41→          <div key={i} className="flex gap-3">
 42→            <Skeleton className="h-8 w-8 rounded-full" />
 43→            <div className="space-y-2 flex-1">
 44→              <Skeleton className="h-4 w-24" />
 45→              <Skeleton className="h-16 w-full" />
 46→            </div>
 47→          </div>
 48→        ))}
 49→      </div>
 50→    );
 51→  }
 52→
 53→  if (error) {
 54→    return (
 55→      <div className="p-4">
 56→        <div className="rounded-lg border border-destructive/50 bg-destructive/10 p-3">
 57→          <p className="text-sm text-destructive">{error}</p>
 58→        </div>
 59→      </div>
 60→    );
 61→  }
 62→
 63→  if (messages.length === 0) {
 64→    return (
 65→      <div className="flex items-center justify-center h-64 text-muted-foreground">
 66→        No messages in this session
 67→      </div>
 68→    );
 69→  }
 70→
 71→  const shouldShowHeader = (index: number): boolean => {
 72→    if (index === 0) return true;
 73→    const prev = messages[index - 1];
 74→    const curr = messages[index];
 75→    if (prev.type !== curr.type) return true;
 76→    // Break grouping when transitioning between real user messages and agent messages
 77→    if (curr.type === 'user' && curr.content && prev.content) {
 78→      const currIsAgent = isAgentMessage(curr.content);
 79→      const prevIsAgent = isAgentMessage(prev.content);
 80→      if (currIsAgent !== prevIsAgent) return true;
 81→    }
 82→    return false;
 83→  };
 84→
 85→  return (
 86→    <div className="w-full px-2">
 87→      {messages.map((message, index) => (
 88→        <div key={message.id} id={`msg-${message.id}`} className="py-1">
 89→          {shouldShowDateSeparator(messages, index) && (
 90→            <DateSeparator timestamp={message.timestamp} />
 91→          )}
 92→          <MessageBubble
 93→            message={message}
 94→            showHeader={shouldShowHeader(index)}
 95→            sourceTool={sourceTool}
 96→            nextToolResults={
 97→              messages[index + 1]?.type === 'user'
 98→                ? parseJsonField<ToolResult[]>(messages[index + 1].tool_results, [])
 99→                : []
100→            }
101→          />
102→        </div>
103→      ))}
104→
105→      {loadingMore && (
106→        <div className="space-y-4 p-4">
107→          {[...Array(3)].map((_, i) => (
108→            <div key={i} className="flex gap-3">
109→              <Skeleton className="h-8 w-8 rounded-full" />
110→              <div className="space-y-2 flex-1">
111→                <Skeleton className="h-4 w-24" />
112→                <Skeleton className="h-12 w-full" />
113→              </div>
114→            </div>
115→          ))}
116→        </div>
117→      )}
118→
119→      {hasMore && (
120→        <LoadMoreSentinel onLoadMore={onLoadMore} loadingMore={loadingMore} />
121→      )}
122→    </div>
123→  );
124→}
