 1→import { useEffect, useRef, useCallback } from 'react';
 2→
 3→interface LoadMoreSentinelProps {
 4→  onLoadMore?: () => void;
 5→  loadingMore?: boolean;
 6→}
 7→
 8→/**
 9→ * Sentinel element that triggers loadMore via IntersectionObserver
10→ * when it scrolls into view.
11→ */
12→export function LoadMoreSentinel({ onLoadMore, loadingMore }: LoadMoreSentinelProps) {
13→  const sentinelRef = useRef<HTMLDivElement>(null);
14→
15→  const handleIntersect = useCallback(
16→    (entries: IntersectionObserverEntry[]) => {
17→      if (entries[0]?.isIntersecting && onLoadMore && !loadingMore) {
18→        onLoadMore();
19→      }
20→    },
21→    [onLoadMore, loadingMore]
22→  );
23→
24→  useEffect(() => {
25→    const el = sentinelRef.current;
26→    if (!el) return;
27→    const observer = new IntersectionObserver(handleIntersect, { threshold: 0.1 });
28→    observer.observe(el);
29→    return () => observer.disconnect();
30→  }, [handleIntersect]);
31→
32→  return <div ref={sentinelRef} className="h-1" />;
33→}
